import numpy as np

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = -1
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = 1

    def print_board(self):
        mapping = {0: ".", -1: "b", 1: "r"}
        for row in self.board:
            print(" ".join(mapping[x] for x in row))

    def move_piece(self, start_pos, end_pos):
        start_row, start_col = start_pos
        end_row, end_col = end_pos
        piece = self.board[start_row][start_col]
        if abs(start_row - end_row) == 1 and abs(start_col - end_col) == 1:
            self.board[start_row][start_col] = 0
            self.board[end_row][end_col] = piece
        elif abs(start_row - end_row) == 2 and abs(start_col - end_col) == 2:
            middle_row, middle_col = (start_row + end_row) // 2, (start_col + end_col) // 2
            if self.board[middle_row][middle_col] * piece < 0:
                self.board[start_row][start_col] = 0
                self.board[end_row][end_col] = piece
                self.board[middle_row][middle_col] = 0

    def is_valid_move(self, start_pos, end_pos):
        start_row, start_col = start_pos
        end_row, end_col = end_pos
        if abs(start_row - end_row) not in [1, 2] or abs(start_col - end_col) != 1:
            return False
        piece = self.board[start_row][start_col]
        if piece == 0 or piece * (end_row - start_row) < 0:
            return False
        middle_pos = ((start_row + end_row) // 2, (start_col + end_col) // 2)
        middle_piece = self.board[middle_pos[0]][middle_pos[1]]
        if abs(start_row - end_row) == 2 and middle_piece != -piece:
            return False
        return True
