import numpy as np

class Piece:
    EMPTY = ' '
    RED = 'R'
    BLACK = 'B'
    RED_KING = 'Rk'
    BLACK_KING = 'Bk'

class Board:
    def __init__(self):
        self.board = np.array([[Piece.EMPTY for _ in range(8)] for _ in range(8)])
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece.BLACK
            for j in range(1, 8, 2):
                self.board[7 - i][j] = Piece.RED

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = Piece.RED

    def switch_player(self):
        if self.current_player == Piece.RED:
            self.current_player = Piece.BLACK
        else:
            self.current_player = Piece.RED

    def make_move(self, from_pos, to_pos):
        from_row, from_col = map(int, from_pos.split(','))
        to_row, to_col = map(int, to_pos.split(','))

        piece = self.board.board[from_row][from_col]
        if piece != self.current_player:
