        red_pieces = np.sum(self.board.board == Piece.RED)
        black_pieces = np.sum(self.board.board == Piece.BLACK)
        if red_pieces == 0:
            return Piece.BLACK
        elif black_pieces == 0:
            return Piece.RED
        return None

